// SDLC Slot Creator
// Bulk-creates empty workflows and transfers them to a project folder.
//
// Required body fields:
//   projectId  — n8n project ID (destination folder)
//   count      — number of slots to create (1–50)
//   baseUrl    — n8n instance URL (e.g. "https://n8n.example.com")
//   apiKey     — n8n REST API key
//
// Optional:
//   names      — array of workflow names (defaults to "Slot 1", "Slot 2", ...)

const input = $input.first().json;

const projectId = input.projectId;
const count = parseInt(input.count, 10);
const names = input.names || [];
const baseUrl = (input.baseUrl || '').replace(/\/$/, '');
const apiKey = input.apiKey;

// --- Validation ---
const missing = [];
if (!projectId) missing.push('projectId');
if (!baseUrl) missing.push('baseUrl');
if (!apiKey) missing.push('apiKey');

if (missing.length > 0) {
  return [{ json: { success: false, error: `Missing required fields: ${missing.join(', ')}` } }];
}
if (isNaN(count) || count < 1 || count > 50) {
  return [{ json: { success: false, error: 'count must be a number between 1 and 50' } }];
}

// --- Create and transfer each slot ---
const headers = {
  'X-N8N-API-KEY': apiKey,
  'Content-Type': 'application/json',
};

const created = [];
const errors = [];

for (let i = 0; i < count; i++) {
  const name = names[i] || `Slot ${i + 1}`;

  try {
    // 1. Create empty workflow (lands in Personal folder)
    const createResp = await fetch(`${baseUrl}/api/v1/workflows`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        name,
        nodes: [],
        connections: {},
        settings: { executionOrder: 'v1' },
      }),
    });

    if (!createResp.ok) {
      const errText = await createResp.text();
      throw new Error(`Create failed (HTTP ${createResp.status}): ${errText}`);
    }

    const workflow = await createResp.json();

    // 2. Transfer to target project folder
    const transferResp = await fetch(
      `${baseUrl}/api/v1/workflows/${workflow.id}/transfer`,
      {
        method: 'PUT',
        headers,
        body: JSON.stringify({ destinationProjectId: projectId }),
      }
    );

    if (!transferResp.ok) {
      const errText = await transferResp.text();
      throw new Error(`Transfer failed (HTTP ${transferResp.status}): ${errText}`);
    }

    created.push({ id: workflow.id, name });
  } catch (err) {
    errors.push({ index: i, name, error: err.message });
  }
}

return [{
  json: {
    success: errors.length === 0,
    created,
    count: created.length,
    requested: count,
    errors,
  },
}];
